import React from 'react'
import c from './add.module.scss'
import { Icons } from '../../assets/icons'
import { API } from '../../api'

const AddProfit = ({ setActive }) => {
  const [count, setCount] = React.useState(1)
  const [data, setData] = React.useState([{ type: 'income', name: '', amount: '' }])

  const handleChange = (index, field, value) => {
    const newData = [...data]
    newData[index] = { ...newData[index], [field]: value }
    setData(newData)
  }

  const handleAddForm = () => {
    setCount(prev => prev + 1)
    setData(prev => [...prev, { type: 'income', name: '', amount: '' }])
  }

  const handleSave = () => {
    const payload = data.map(item => ({
      type: 'income',
      name: item.name || '',
      amount: parseFloat(item.amount) || 0
    }))

    API.postTransactions(payload)
      .then(() => {
        setActive(false)
      })
      .catch(err => console.error(err))
  }

  return (
    <div className={c.addExpense}>
      <div className={c.addExpense__header}>
        <h2>–Ē–ĺ–Ī–į–≤–ł—ā—Ć –Ņ—Ä–ł–Ī—č–Ľ–ł</h2>
      </div>

      {Array.from({ length: count }).map((_, index) => (
        <div
          key={index}
          className={c.addExpense__form}
        >
          <div className={c.addExpense__form__item}>
            <label htmlFor={`name-${index}`}>–Ě–į–ł–ľ–Ķ–Ĺ–ĺ–≤–į–Ĺ–ł–Ķ –Ņ—Ä–ł–Ī—č–Ľ–ł</label>
            <input
              type="text"
              id={`name-${index}`}
              placeholder="–í–≤–Ķ–ī–ł—ā–Ķ –Ĺ–į–ł–ľ–į–Ķ–Ĺ–ĺ–≤–į–Ĺ–ł–Ķ"
              value={data[index]?.name || ''}
              onChange={e => handleChange(index, 'name', e.target.value)}
            />
          </div>
          <div className={c.addExpense__form__item}>
            <label htmlFor={`amount-${index}`}>–°—É–ľ–ľ–į</label>
            <input
              type="number"
              id={`amount-${index}`}
              placeholder="–í–≤–Ķ–ī–ł—ā–Ķ —Ā—É–ľ–ľ—É"
              value={data[index]?.amount || ''}
              onChange={e => handleChange(index, 'amount', e.target.value)}
            />
          </div>
        </div>
      ))}

      <button onClick={handleAddForm}>
        <img src={Icons.plus} alt="plus" />
        –Ē–ĺ–Ī–į–≤–ł—ā—Ć –Ĺ–į–ł–ľ–Ķ–Ĺ–ĺ–≤–į–Ĺ–ł–Ķ
      </button>

      <div className={c.res}>
        <button onClick={() => setActive(false)}>
          –ě—ā–ľ–Ķ–Ĺ–ł—ā—Ć
        </button>
        <button onClick={handleSave}>
          <img src={Icons.addGreen} alt="add" />
          –°–ĺ—Ö—Ä–į–Ĺ–ł—ā—Ć
        </button>
      </div>
    </div>
  )
}

export default AddProfit
